122:         devShells.default = pkgs.mkShell {
123:           buildInputs = with pkgs; [
124:             nixpkgs-fmt
125:             nil
126:             statix
127:             deadnix
128: 
129:             cachix
130:             direnv
131: 
132:           ] ++ (if pkgs.stdenv.isDarwin then [
