143:             echo "  - nil: Nix language server"
144:             echo "  - statix: Linter for nix"
145:             echo "  - deadnix: Find unused code"
146:             echo "  - cachix: Binary cache management"
147:             echo "  - direnv: Environment management"
148:             ${if pkgs.stdenv.isDarwin then ''
149:               echo "  - darwin-rebuild: System configuration management"
150:             '' else ''
151:               echo "  - nixos-rebuild: NixOS system management"
152:               echo "  - nixos-generators: ISO/VM image generation"
153:             ''}
154:           '';
155:         };
156: 
157:         formatter = pkgs.nixpkgs-fmt;
158:       };
159: 
160:       flake = {
161:         darwinConfigurations = {
162:           "mbp-m2" = inputs.nix-darwin.lib.darwinSystem {
163:             specialArgs = {
164:               inherit inputs;
165:               hostSystem = "aarch64-darwin";
166:               headMode = "graphical";
167:               # Make system architecture available for conditional logic
168:               inherit (inputs.nixpkgs.lib) systems;
169:               # Helper function to get packages for different systems
170:               pkgsFor = system: import inputs.nixpkgs {
171:                 inherit system;
172:                 config.allowUnfree = true;
173:                 overlays = [ (import ./overlays/unstable.nix inputs) ];
174:               };
175:             };
176:             modules = [
177:               inputs.sops-nix.darwinModules.sops
178:               inputs.axiom-deploy-annotation.darwinModules.default
179:               # Apply overlays to the main system packages
180:               ({ config, ... }: {
181:                 nixpkgs = {
182:                   hostPlatform = "aarch64-darwin";
183:                   config.allowUnfree = true;
184:                   overlays = [ (import ./overlays/unstable.nix inputs) ];
185:                 };
186:                 # track git revision for deploy annotations
187:                 system.configurationRevision = flakeRevision;
188:                 
189:                 services.axiom-deploy-annotation = {
190:                   enable = true;
191:                   configPath = config.sops.secrets."axiom.toml".path;
192:                   dataset = "papertrail";
193:                   datasets = [ "papertrail" "host-metrics" ];
194:                   repositoryUrl = "https://github.com/bdsqqq/dots";
195:                 };
196:               })
